_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_main, vUv ).xyz;

    // feather pen
    ret = max(ret, texture( sampler_main, (vUv-0.5)*(1-8*length(uTexSize.zw)) + 0.5 ).xyz);
    ret = max(ret, texture( sampler_main, (vUv-0.5)*(1+8*length(uTexSize.zw)) + 0.5 ).xyz);

    // darken over uTime
    ret = (ret-0.03)*0.98;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = (vUv-.5)*.9 + .5;
uv1 = (vUv-center)*uAspect.xy;

dist = MinDistB(vUv);
bdist = mix(dist,GetDistB(vUv),.2);
dist_c = clamp(GetDistB2 (center),.1,.4); //center distance

vec3 uv2 = multiply(vec3((vUv-.5)*MinDistB(vUv),MinDistB(vUv))/myzoom,RotMat)+CamPos;
glow = pow(sat(texture(sampler_noise_hq,.02*uv2).r-.6)*2,2);
//vUv += .003*glow*(texture(sampler_noise_mq,vUv*2+vec2(0,uTime/4).xy-.5));

float focus = sat(abs(GetDistB2(vUv)-dist_c)*1+.2);
float struc = GetBlurX(vUv,focus).r;

glow = sat(1-exp(-(GetBlur1(vUv).r))-.2);
q18 = 1;
ret = pow(struc,1) * (.2+(1-focus) *mix(dist,1-dist,q18)) * (1+.5*sin(uv2));
ret = mix(ret, vec3(0,1,glow*3), glow);

//distant light
ret += pow(1-GetBlurX(vUv,.8).b,3)*(.5+.5*slow_roam_cos) *q19;

//Lamp
uv3 = uv1;
lamp = clamp01(1-4*length(uv3))*(struc)*clamp01(1-2*bdist)*1.8;
//ret += (1-lum(ret))*lamp;
ret = 1-exp((-2)*ret);
//ret = GetPixel(vUv).r;

float lum = ret.x * 0.3 + ret.y*0.5 + ret.z*0.2;
ret = lum * 3 - vec3(0, 1, 2);


  fragColor = ret;
}
